function symmetricDiff(a, b) {
  const setA = new Set(a);
  const setB = new Set(b);
  const out = [];
  for (const x of setA) if (!setB.has(x)) out.push(x);
  for (const x of setB) if (!setA.has(x)) out.push(x);
  return out;
}

function distinctCount(lists) {
  const all = new Set();
  for (let i = 0; i < lists.length; i++) { const lst = lists[i]; for (let j = 0; j < lst.length; j++) all.add(lst[j]); }
  return all.size;
}
